{
  "app": {
    "name": "GitLab CI Dashboard",
    "one_sentence": "A self-hosted dashboard providing global visibility into GitLab CI pipelines and schedules across entire groups, with server-side caching and optional pipeline control.",
    "inspired_by": null
  },
  "core_loop": "Users configure the dashboard with a GitLab API token and base URL, then view aggregated pipeline and schedule statuses across a GitLab group; they can filter, search, and optionally trigger pipeline actions like restart or cancel if using a read/write token.",
  "screens": [
    {
      "id": "main",
      "name": "Pipeline Overview",
      "purpose": "Display all latest pipeline statuses, schedules, and job details within a GitLab group with filtering and search capabilities.",
      "primary_actions": [
        "Filter pipelines by status",
        "Search projects within group",
        "Restart failed pipelines",
        "Cancel running pipelines",
        "Start new pipelines",
        "Download job artifacts"
      ]
    }
  ],
  "rust_commands": [
    {
      "name": "fetch_pipelines",
      "purpose": "Retrieve and cache pipeline data from GitLab API for a given group using server-side token authentication.",
      "async": true,
      "input": {},
      "output": {}
    },
    {
      "name": "trigger_pipeline_action",
      "purpose": "Perform write operations on pipelines (restart, cancel, create) via GitLab API when configured with a read/write token.",
      "async": true,
      "input": {},
      "output": {}
    }
  ],
  "data_model": {
    "tables": [
      {
        "name": "pipelines",
        "fields": [
          {
            "name": "id",
            "type": "string"
          },
          {
            "name": "status",
            "type": "string"
          },
          {
            "name": "project_name",
            "type": "string"
          },
          {
            "name": "created_at",
            "type": "timestamp"
          }
        ]
      },
